<?php
declare(strict_types=1);
require_once dirname(__DIR__).'/includes/cms.php';
$pdo=obtenerConexion();$capId=cmsId($_GET['capacitacion_id']??0);$caps=$pdo->query("SELECT id,nombre FROM asignaturas WHERE deleted_at IS NULL ORDER BY nombre")->fetchAll();if(!$capId&&$caps)$capId=(int)$caps[0]['id'];
$q=$pdo->prepare("SELECT s.*,CONCAT(u.nombre,' ',u.apellido) docente FROM capacitacion_secciones s JOIN usuarios u ON u.id=s.docente_id WHERE s.asignatura_id=:a ORDER BY s.id");$q->execute(['a'=>$capId]);$secciones=$q->fetchAll();$q=$pdo->prepare("SELECT u.id,CONCAT(u.nombre,' ',u.apellido) nombre FROM docentes_asignaturas da JOIN usuarios u ON u.id=da.docente_id WHERE da.asignatura_id=:a AND da.estado='activo' AND u.estado='activo' AND u.deleted_at IS NULL");$q->execute(['a'=>$capId]);$docentes=$q->fetchAll();
cmsCabecera('Secciones de capacitación','capacitaciones/secciones.php','Cupo máximo 30, docente autorizado y control de apertura.');
?><div class="card card-rounded mb-4"><div class="card-body"><form class="row g-3 align-items-end"><div class="col-md-8"><label class="form-label">Capacitación</label><select class="form-select" name="capacitacion_id"><?php foreach($caps as$c):?><option value="<?=$c['id']?>" <?=$capId===$c['id']?'selected':''?>><?=atenea_e($c['nombre'])?></option><?php endforeach;?></select></div><div class="col-md-4"><button class="btn btn-primary text-white">Ver secciones</button></div></form></div></div><div class="card card-rounded mb-4"><div class="card-body"><h2 class="h5">Crear sección</h2><?php if(!$docentes):?><div class="alert alert-warning">Autoriza primero un docente elegible en la capacitación.</div><?php else:?><form class="row g-3" method="post" action="seccion-accion.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="accion" value="crear"><input type="hidden" name="capacitacion_id" value="<?=$capId?>"><div class="col-md-3"><input class="form-control" name="codigo" maxlength="80" placeholder="Código" required></div><div class="col-md-3"><input class="form-control" name="nombre" maxlength="180" placeholder="Nombre" required></div><div class="col-md-3"><select class="form-select" name="docente_id" required><?php foreach($docentes as$d):?><option value="<?=$d['id']?>"><?=atenea_e($d['nombre'])?></option><?php endforeach;?></select></div><div class="col-md-3"><input class="form-control" type="number" name="capacidad" min="1" max="30" value="30" required></div><div class="col-md-3"><input class="form-control" type="date" name="fecha_inicio"></div><div class="col-md-3"><input class="form-control" type="date" name="fecha_finalizacion"></div><div class="col-md-4"><input class="form-control" name="horario" maxlength="255" placeholder="Horario"></div><div class="col-md-2"><button class="btn btn-success w-100">Crear</button></div></form><?php endif;?></div></div><div class="card card-rounded"><div class="card-body"><div class="table-responsive"><table class="table align-middle"><thead><tr><th>Sección</th><th>Docente</th><th>Cupo</th><th>Fechas/horario</th><th>Estado</th><th>Acciones</th></tr></thead><tbody><?php foreach($secciones as$s):?><tr><td><strong><?=atenea_e($s['codigo'])?></strong><br><?=atenea_e($s['nombre'])?></td><td><form class="d-flex gap-2" method="post" action="seccion-accion.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="accion" value="docente"><input type="hidden" name="seccion_id" value="<?=$s['id']?>"><input type="hidden" name="capacitacion_id" value="<?=$capId?>"><select class="form-select form-select-sm" name="docente_id"><?php foreach($docentes as$d):?><option value="<?=$d['id']?>" <?=$s['docente_id']==$d['id']?'selected':''?>><?=atenea_e($d['nombre'])?></option><?php endforeach;?></select><button class="btn btn-sm btn-outline-primary">Cambiar</button></form></td><td><?=$s['cantidad_actual']?> / <?=$s['capacidad_maxima']?></td><td><?=atenea_e(($s['fecha_inicio']?:'Sin fecha').' · '.($s['horario']?:'Sin horario'))?></td><td><?=atenea_e($s['estado'])?></td><td><form method="post" action="seccion-accion.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="accion" value="<?=$s['estado']==='abierta'?'cerrar':'abrir'?>"><input type="hidden" name="seccion_id" value="<?=$s['id']?>"><input type="hidden" name="capacitacion_id" value="<?=$capId?>"><button class="btn btn-sm btn-outline-warning"><?=$s['estado']==='abierta'?'Cerrar':'Abrir'?></button></form></td></tr><?php endforeach;?><?php if(!$secciones):?><tr><td colspan="6" class="text-center py-5">No hay secciones.</td></tr><?php endif;?></tbody></table></div></div></div><?php cmsPie();
